import { login } from './authApi';
import { loginSchema } from './login.schema';

const getSafeReturnUrl = (rawReturnUrl) => {
    if (typeof rawReturnUrl !== 'string') {
        return '/home';
    }

    let decodedReturnUrl;

    try {
        decodedReturnUrl = decodeURIComponent(rawReturnUrl);
    } catch {
        return '/home';
    }

    if (
        !decodedReturnUrl.startsWith('/') ||
        decodedReturnUrl.startsWith('//') ||
        decodedReturnUrl.includes('://')
    ) {
        return '/home';
    }

    return decodedReturnUrl;
};

export const LoginPage = () => {
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const setUser = useAuthStore((state) => state.setUser);
    const returnUrl = getSafeReturnUrl(searchParams.get('returnUrl') || '/home');
