const buildPageItems = (currentPage, totalPages) => {
    if (totalPages <= 1) return [];
    if (totalPages <= 7) {
        return Array.from({ length: totalPages }, (_, i) => ({ type: 'page', value: i + 1 }));
    }
    const pages = new Set([1, totalPages, currentPage - 1, currentPage, currentPage + 1]);
    const ordered = [...pages].filter((p) => p >= 1 && p <= totalPages).sort((a, b) => a - b);
    const items = [];
    let last = 0;
    ordered.forEach((p) => {
        if (p - last > 1) items.push({ type: 'ellipsis', key: `e-${last}-${p}` });
        items.push({ type: 'page', value: p });
        last = p;
    });
    return items;
};

export const CardList = ({ pageData, pageSizeOptions = [10, 20, 50, 100], onPageChange, renderItem }) => {
