, "content": "import { createContext, use } from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuthStore } from '@/store/useAuthStore';

export const AuthReadyContext = createContext(false);

export const ProtectedRoute = ({ children, ready = false }) => {
    const contextReady = use(AuthReadyContext);
    const isAuthenticated = useAuthStore((state) => state.isAuthenticated);
    const location = useLocation();
    const isAuthResolved = ready || contextReady;

    if (!isAuthResolved) {
        return null;
    }

    if (!isAuthenticated) {
        const returnUrl = encodeURIComponent(location.pathname);

        return <Navigate to={`/login?returnUrl=${returnUrl}`} replace />;
    }

    return children;
};
