      --shadow-sm:   0 1px 4px oklch(0% 0 0 / 0.06), 0 1px 2px oklch(0% 0 0 / 0.04);
      --shadow-md:   0 4px 12px oklch(0% 0 0 / 0.08), 0 2px 4px oklch(0% 0 0 / 0.04);
      --shadow-lg:   0 12px 40px oklch(0% 0 0 / 0.13), 0 4px 12px oklch(0% 0 0 / 0.06);
      --shadow-card-hover: 0 8px 28px oklch(0% 0 0 / 0.11), 0 3px 8px oklch(0% 0 0 / 0.05);
    }

